-- Treinova beta: sincroniza a biblioteca global com imagens especificas de exercicios.
-- Data: 2026-06-05
-- Seguro/idempotente: atualiza apenas public.exercises.is_library = true e preserva uploads customizados.

begin;

create or replace function pg_temp.treinova_exercise_image_key(value text)
returns text
language sql
immutable
as $$
  select translate(
    lower(coalesce(value, '')),
    'áàâãäåéèêëíìîïóòôõöúùûüçñ',
    'aaaaaaeeeeiiiiooooouuuucn'
  );
$$;

create temp table _treinova_exercise_image_map (
  name_key text primary key,
  image_url text not null
) on commit drop;

on conflict (name_key) do nothing;

update public.exercises e
set image_url = m.image_url
from _treinova_exercise_image_map m
where e.is_library = true
  and pg_temp.treinova_exercise_image_key(e.name) = m.name_key
  and (
    e.image_url is null
    or btrim(e.image_url) = ''
    or e.image_url like '/assets/exercises/%'
    or e.image_url like 'assets/exercises/%'
    or e.image_url like 'data:image/svg+xml%'
  )
  and e.image_url is distinct from m.image_url;

commit;
